// ─── PALETTE & UI TOKENS ─────────────────────────────────────────
const COLORS = {
  0:{fill:"#1a1008",label:"Black",code:"B"},
  1:{fill:"#f5efe0",label:"White",code:"W"},
  2:{fill:"#3b5bdb",label:"Blue", code:"L"},
  3:{fill:"#c0392b",label:"Red",  code:"R"},
};
const UI={bg:"#0e0b07",panel:"#0a0805",border:"#2a1e0a",border2:"#1e1508",
  gold:"#e8c87a",dim:"#7a5c2e",dimmer:"#4a3010",dimmest:"#2a1e0a",
  text:"#c9a96e",blue:"#6b82db",red:"#e05545"};

// DXF ring definitions (mm, centred at 0,0)
const DXF_RINGS = [
  {name:"Soundhole",   rIn:0,     rOut:40.8, color:"rgba(14,11,7,1)",   fill:true},
  {name:"Inner Border",rIn:40.8,  rOut:41.8, color:"#3a2e1a",           fill:true},
  {name:"Pattern Zone",rIn:41.8,  rOut:47.8, color:"transparent",       fill:false},
  {name:"Ebony Ring",  rIn:47.8,  rOut:49.3, color:"#1a1008",           fill:true},
  {name:"Green Ring",  rIn:49.3,  rOut:50.8, color:"#2d6a4f",           fill:true},
];

// ─── HELPERS ─────────────────────────────────────────────────────
function countRow(grid,row,cols){const c={0:0,1:0,2:0,3:0};for(let i=0;i<cols;i++)c[grid[row]?.[i]??0]++;return c;}
function countTotals(grid,rows,cols){const t={0:0,1:0,2:0,3:0};for(let r=0;r<rows;r++){const rc=countRow(grid,r,cols);Object.keys(t).forEach(k=>t[k]+=rc[k]);}return t;}
function mirrorPoints(r,c,rows,cols,mode){const pts=[[r,c]];if(mode==="H"||mode==="4")pts.push([r,cols-1-c]);if(mode==="V"||mode==="4")pts.push([rows-1-r,c]);if(mode==="4")pts.push([rows-1-r,cols-1-c]);return[...new Map(pts.map(p=>[p.join(","),p])).values()];}

// ─── DXF CANVAS ──────────────────────────────────────────────────
function DXFCanvas({scale,darkColor,lightColor,visLayers,canvasSize}){
  const canvasRef=useRef(null);
  useEffect(()=>{
    const canvas=canvasRef.current; if(!canvas)return;
    canvas.width=canvasSize; canvas.height=canvasSize;
    const ctx=canvas.getContext("2d");
    const cx=canvasSize/2, cy=canvasSize/2;
    ctx.fillStyle=UI.bg; ctx.fillRect(0,0,canvasSize,canvasSize);

    const sc=scale; // px per mm

    // Draw ring fills bottom-up
    DXF_RINGS.forEach(ring=>{
      if(!visLayers[ring.name]) return;
      if(ring.fill && ring.color!=="transparent"){
        ctx.beginPath();
        ctx.arc(cx,cy,ring.rOut*sc,0,Math.PI*2);
        if(ring.rIn>0){ctx.arc(cx,cy,ring.rIn*sc,0,Math.PI*2,true);}
        ctx.fillStyle=ring.color;
        ctx.fill("evenodd");
      }
    });

    // Draw tile polygons (only inside pattern zone)
    const drawTiles=(tiles, color)=>{
      if(!color) return;
      ctx.fillStyle=color;
      ctx.strokeStyle="rgba(90,60,20,0.2)";
      ctx.lineWidth=0.4;
      tiles.forEach(flat=>{
        ctx.beginPath();
        ctx.moveTo(cx+flat[0]*sc, cy-flat[1]*sc);
        ctx.lineTo(cx+flat[2]*sc, cy-flat[3]*sc);
        ctx.lineTo(cx+flat[4]*sc, cy-flat[5]*sc);
        ctx.lineTo(cx+flat[6]*sc, cy-flat[7]*sc);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
      });
    };

    if(visLayers["HB_DARK"])  drawTiles(DXF.d, darkColor);
    if(visLayers["HB_LIGHT"]) drawTiles(DXF.l, lightColor);

    // Ring borders
    DXF_RINGS.forEach(ring=>{
      if(!visLayers[ring.name]) return;
      ctx.strokeStyle="rgba(200,160,50,0.35)";
      ctx.lineWidth=0.6;
      [ring.rIn,ring.rOut].forEach(r=>{
        if(r>0){ctx.beginPath();ctx.arc(cx,cy,r*sc,0,Math.PI*2);ctx.stroke();}
      });
    });

    // Center crosshair
    ctx.strokeStyle="rgba(200,160,50,0.1)";ctx.lineWidth=0.5;
    ctx.beginPath();ctx.moveTo(cx,0);ctx.lineTo(cx,canvasSize);ctx.stroke();
    ctx.beginPath();ctx.moveTo(0,cy);ctx.lineTo(canvasSize,cy);ctx.stroke();

    // Scale bar (10mm)
    const barLen=10*sc;
    ctx.strokeStyle="rgba(200,160,50,0.7)";ctx.lineWidth=1.5;
    ctx.beginPath();ctx.moveTo(16,canvasSize-16);ctx.lineTo(16+barLen,canvasSize-16);ctx.stroke();
    ctx.fillStyle="rgba(200,160,50,0.7)";ctx.font="9px 'Courier New'";
    ctx.fillText("10mm",16,canvasSize-22);

  },[scale,darkColor,lightColor,visLayers,canvasSize]);

  return(<canvas ref={canvasRef} style={{borderRadius:"4px",border:`1px solid ${UI.border}`,display:"block",maxWidth:"100%"}}/>);
}

// ─── PARAMETRIC CANVAS ───────────────────────────────────────────
function ParametricCanvas({theta,w,h,rIn,rOut,toothColors,showAnnulus,showGrid,canvasSize}){
  const canvasRef=useRef(null);
  useEffect(()=>{
    const canvas=canvasRef.current;if(!canvas)return;
    canvas.width=canvasSize;canvas.height=canvasSize;
    const ctx=canvas.getContext("2d");
    const cx=canvasSize/2,cy=canvasSize/2;
    ctx.fillStyle=UI.bg;ctx.fillRect(0,0,canvasSize,canvasSize);
    const rad=theta*Math.PI/180;
    const ax=2*w,bx=w,by=2*h;
    const R=Math.max(rOut*1.5+w*4,canvasSize*.8);
    const steps=Math.ceil(R/Math.min(w,h))+6;
    ctx.save();ctx.beginPath();ctx.rect(0,0,canvasSize,canvasSize);ctx.clip();
    for(let i=-steps;i<=steps;i++){
      for(let j=-steps;j<=steps;j++){
        const px=cx+i*ax+j*bx,py=cy+j*by;
        const dist=Math.sqrt((px-cx)**2+(py-cy)**2);
        if(showAnnulus&&(dist>rOut+Math.max(w,h)||dist<rIn-Math.max(w,h)))continue;
        const tAngle=(i+j)%2===0?rad:-rad;
        const cos=Math.cos(tAngle),sin=Math.sin(tAngle);
        const corners=[[w/2,h/2],[w/2,-h/2],[-w/2,-h/2],[-w/2,h/2]];
        const pts=corners.map(([lx,ly])=>[px+lx*cos-ly*sin,py+lx*sin+ly*cos]);
        const anyIn=pts.some(([x,y])=>{const d=Math.sqrt((x-cx)**2+(y-cy)**2);return!showAnnulus||(d>=rIn&&d<=rOut);});
        if(showAnnulus&&!anyIn)continue;
        const fillColor=toothColors[(i+j)%2===0?0:1];
        if(showAnnulus){ctx.save();ctx.beginPath();ctx.arc(cx,cy,rOut,0,Math.PI*2);ctx.arc(cx,cy,rIn,0,Math.PI*2,true);ctx.clip("evenodd");}
        ctx.beginPath();ctx.moveTo(pts[0][0],pts[0][1]);for(let k=1;k<pts.length;k++)ctx.lineTo(pts[k][0],pts[k][1]);ctx.closePath();
        ctx.fillStyle=fillColor;ctx.fill();
        ctx.strokeStyle="rgba(90,60,20,.3)";ctx.lineWidth=.6;ctx.stroke();
        if(showAnnulus)ctx.restore();
      }
    }
    if(showAnnulus){
      ctx.strokeStyle="rgba(200,160,50,.45)";ctx.lineWidth=1;ctx.setLineDash([4,4]);
      ctx.beginPath();ctx.arc(cx,cy,rOut,0,Math.PI*2);ctx.stroke();
      ctx.beginPath();ctx.arc(cx,cy,rIn,0,Math.PI*2);ctx.stroke();
      ctx.setLineDash([]);
    }
    if(showGrid){ctx.strokeStyle="rgba(200,160,50,.1)";ctx.lineWidth=.5;ctx.beginPath();ctx.moveTo(cx,0);ctx.lineTo(cx,canvasSize);ctx.stroke();ctx.beginPath();ctx.moveTo(0,cy);ctx.lineTo(canvasSize,cy);ctx.stroke();}
    ctx.restore();
  },[theta,w,h,rIn,rOut,toothColors,showAnnulus,showGrid,canvasSize]);
  return(<canvas ref={canvasRef} style={{borderRadius:"4px",border:`1px solid ${UI.border}`,display:"block",maxWidth:"100%"}}/>);
}

// ─── HERRINGBONE PANEL ───────────────────────────────────────────
function HerringbonePanel(){
  const[mode,setMode]=useState("dxf"); // "dxf" | "parametric"

  // DXF mode state
  const[scale,setScale]=useState(4.2);
  const[darkColor,setDarkColor]=useState("#1a1008");
  const[lightColor,setLightColor]=useState("#d4b483");
  const[visLayers,setVisLayers]=useState({
    "Soundhole":true,"Inner Border":true,"Pattern Zone":true,
    "Ebony Ring":true,"Green Ring":true,"HB_DARK":true,"HB_LIGHT":true
  });

  // Parametric mode state
  const[theta,setTheta]=useState(45);
  const[w,setW]=useState(14);
  const[h,setH]=useState(28);
  const[rIn,setRIn]=useState(80);
  const[rOut,setROut]=useState(130);
  const[showAnn,setShowAnn]=useState(true);
  const[showGrid,setShowGrid]=useState(true);
  const[tooth0,setTooth0]=useState("#1a1008");
  const[tooth1,setTooth1]=useState("#f5efe0");

  const toggleLayer=(name)=>setVisLayers(prev=>({...prev,[name]:!prev[name]}));

  const knob=(label,val,set,min,max,step=1,unit="")=>(
    <div style={{marginBottom:"9px"}}>
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:"2px"}}>
        <span style={{fontSize:"9px",letterSpacing:"1px",color:UI.dim}}>{label}</span>
        <span style={{fontSize:"10px",color:UI.gold}}>{val}{unit}</span>
      </div>
      <input type="range" min={min} max={max} step={step} value={val}
        onChange={e=>set(Number(e.target.value))} style={{width:"100%",accentColor:"#c9a96e"}}/>
    </div>
  );

  return(
    <div>
      {/* Mode switcher */}
      <div style={{display:"flex",gap:"4px",marginBottom:"14px",alignItems:"center"}}>
        {[["dxf","DXF Exact  ✦ parquet_herringbone_rosette.dxf"],["parametric","Parametric Generator"]].map(([v,l])=>(
          <div key={v} onClick={()=>setMode(v)} style={{
            padding:"5px 12px",cursor:"pointer",fontSize:"10px",letterSpacing:"1px",
            border:mode===v?"1px solid #c9a96e":"1px solid #2a1e0a",borderRadius:"3px",
            background:mode===v?"#1e1508":"#0a0805",color:mode===v?UI.gold:UI.dim,
            transition:"all .12s",
          }}>{l}</div>
        ))}
      </div>

      <div style={{display:"flex",gap:"16px",flexWrap:"wrap"}}>

        {/* ── LEFT CONTROLS ── */}
        <div style={{width:"190px",flexShrink:0}}>

          {mode==="dxf" && <>
            {/* DXF metadata card */}
            <div style={{padding:"10px",background:UI.panel,border:`1px solid ${UI.border}`,borderRadius:"4px",marginBottom:"10px"}}>
              <div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"8px"}}>DXF SOURCE</div>
              {[["File","parquet_herringbone_rosette.dxf"],["Units","mm"],["Tooth w","1.0 mm"],["Tooth h","2.0 mm"],["θ nominal","45°"],["Dark tiles","596"],["Light tiles","602"],["Total tiles","1,198"]].map(([k,v])=>(
                <div key={k} style={{display:"flex",justifyContent:"space-between",padding:"2px 0",borderBottom:`1px solid ${UI.dimmest}`}}>
                  <span style={{fontSize:"8px",color:UI.dimmer}}>{k}</span>
                  <span style={{fontSize:"9px",color:UI.text,fontWeight:"bold"}}>{v}</span>
                </div>
              ))}
            </div>

            {/* Scale */}
            <div style={{padding:"10px",background:UI.panel,border:`1px solid ${UI.border}`,borderRadius:"4px",marginBottom:"10px"}}>
              <div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"8px"}}>VIEW</div>
              {knob("Scale (px/mm)",scale,setScale,1,8,0.1," px/mm")}
              <div style={{fontSize:"8px",color:UI.dimmer}}>Canvas = {(canvasSz/scale).toFixed(1)}mm view</div>
            </div>

            {/* Colors */}
            <div style={{padding:"10px",background:UI.panel,border:`1px solid ${UI.border}`,borderRadius:"4px",marginBottom:"10px"}}>
              <div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"8px"}}>VENEER COLORS</div>
              {[["HB_DARK (dark wood)",darkColor,setDarkColor],["HB_LIGHT (maple/spruce)",lightColor,setLightColor]].map(([l,v,s])=>(
                <div key={l} style={{display:"flex",alignItems:"center",gap:"7px",marginBottom:"7px"}}>
                  <input type="color" value={v} onChange={e=>s(e.target.value)}
                    style={{width:"26px",height:"22px",border:`1px solid ${UI.border}`,borderRadius:"2px",cursor:"pointer",padding:"1px"}}/>
                  <span style={{fontSize:"9px",color:UI.dim,lineHeight:1.2}}>{l}</span>
                </div>
              ))}
            </div>

            {/* Layer visibility */}
            <div style={{padding:"10px",background:UI.panel,border:`1px solid ${UI.border}`,borderRadius:"4px"}}>
              <div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"8px"}}>LAYERS</div>
              {[
                ["HB_DARK","Dark tiles"],["HB_LIGHT","Light tiles"],
                ["Soundhole","Soundhole (r=40.8)"],
                ["Inner Border","Inner border (40.8–41.8)"],
                ["Pattern Zone","Pattern zone (41.8–47.8)"],
                ["Ebony Ring","Ebony ring (47.8–49.3)"],
                ["Green Ring","Green ring (49.3–50.8)"],
              ].map(([key,label])=>(
                <div key={key} onClick={()=>toggleLayer(key)} style={{
                  display:"flex",alignItems:"center",gap:"7px",
                  padding:"3px 5px",marginBottom:"2px",cursor:"pointer",
                  border:visLayers[key]?"1px solid #3a2e1a":"1px solid #1a1208",
                  borderRadius:"2px",background:visLayers[key]?"#12100a":"transparent",
                }}>
                  <div style={{width:"8px",height:"8px",borderRadius:"1px",background:visLayers[key]?"#c9a96e":"#2a1e0a",flexShrink:0}}/>
                  <span style={{fontSize:"9px",color:visLayers[key]?UI.text:UI.dimmer}}>{label}</span>
                </div>
              ))}
            </div>
          </>}

          {mode==="parametric" && <>
            <div style={{padding:"10px",background:UI.panel,border:`1px solid ${UI.border}`,borderRadius:"4px",marginBottom:"10px"}}>
              <div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"8px"}}>TOOTH GEOMETRY</div>
              {knob("θ — Rotation",theta,setTheta,0,90,1,"°")}
              {knob("w — Width",w,setW,4,40,1," px")}
              {knob("h — Height",h,setH,8,80,2," px")}
              <div style={{fontSize:"8px",color:UI.dimmer}}>h/w = {(h/w).toFixed(2)} {Math.abs(h/w-2)<.05?"✓ 2:1 (matches DXF)":""}</div>
            </div>
            <div style={{padding:"10px",background:UI.panel,border:`1px solid ${UI.border}`,borderRadius:"4px",marginBottom:"10px"}}>
              <div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"8px"}}>ANNULUS</div>
              {knob("r_in",rIn,setRIn,10,200,2," px")}
              {knob("r_out",rOut,setROut,20,220,2," px")}
              <div style={{fontSize:"8px",color:UI.dimmer}}>Width: {rOut-rIn} px</div>
            </div>
            <div style={{padding:"10px",background:UI.panel,border:`1px solid ${UI.border}`,borderRadius:"4px",marginBottom:"10px"}}>
              <div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"8px"}}>COLORS</div>
              {[["Even",tooth0,setTooth0],["Odd",tooth1,setTooth1]].map(([l,v,s])=>(
                <div key={l} style={{display:"flex",alignItems:"center",gap:"7px",marginBottom:"6px"}}>
                  <input type="color" value={v} onChange={e=>s(e.target.value)}
                    style={{width:"26px",height:"22px",border:`1px solid ${UI.border}`,borderRadius:"2px",cursor:"pointer",padding:"1px"}}/>
                  <span style={{fontSize:"10px",color:UI.dim}}>{l} tiles</span>
                </div>
              ))}
            </div>
            <div style={{padding:"10px",background:UI.panel,border:`1px solid ${UI.border}`,borderRadius:"4px"}}>
              <div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"6px"}}>DISPLAY</div>
              {[[showAnn,setShowAnn,"Annulus ring"],[showGrid,setShowGrid,"Center grid"]].map(([v,s,l])=>(
                <div key={l} onClick={()=>s(!v)} style={{padding:"4px 7px",marginBottom:"3px",cursor:"pointer",fontSize:"10px",border:v?"1px solid #c9a96e":"1px solid #2a1e0a",borderRadius:"3px",background:v?"#1e1508":"transparent",color:v?UI.gold:UI.dim}}>{l}</div>
              ))}
            </div>
          </>}
        </div>

        {/* ── CANVAS ── */}
        <div style={{flex:1,minWidth:0}}>
          {mode==="dxf"
            ? <DXFCanvas scale={scale} darkColor={visLayers["HB_DARK"]?darkColor:null} lightColor={visLayers["HB_LIGHT"]?lightColor:null} visLayers={visLayers} canvasSize={canvasSz}/>
            : <ParametricCanvas theta={theta} w={w} h={h} rIn={rIn} rOut={rOut} toothColors={[tooth0,tooth1]} showAnnulus={showAnn} showGrid={showGrid} canvasSize={canvasSz}/>
          }

          {/* Info bar */}
          {mode==="dxf" && (
            <div style={{marginTop:"10px",padding:"10px",background:UI.panel,border:`1px solid ${UI.border}`,borderRadius:"4px"}}>
              <div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"8px"}}>DXF GEOMETRY SUMMARY</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"4px"}}>
                {[
                  ["Tooth w × h","1.0 × 2.0 mm"],["θ (nominal)","45°"],
                  ["a vector","(2.0, 0) mm"],["b vector","(1.0, 2.0) mm"],
                  ["Pattern zone","41.8 – 47.8 mm"],["Ring width","6.0 mm"],
                  ["Total diameter","101.6 mm"],["Tile count","1,198"],
                ].map(([k,v])=>(
                  <div key={k} style={{display:"flex",justifyContent:"space-between",padding:"3px 6px",background:UI.bg,borderRadius:"2px",border:`1px solid ${UI.border2}`}}>
                    <span style={{fontSize:"8px",color:UI.dimmer}}>{k}</span>
                    <span style={{fontSize:"9px",color:UI.gold,fontWeight:"bold"}}>{v}</span>
                  </div>
                ))}
              </div>
              <div style={{marginTop:"8px",fontSize:"8px",color:UI.dimmer,lineHeight:"1.7"}}>
                <span style={{color:UI.dim}}>Layers extracted: </span>
                SOUNDHOLE · INNER_BORDER · PATTERN_ZONE · HB_DARK (596 tiles) · HB_LIGHT (602 tiles) · EBONY_RING · GREEN_RING
              </div>
            </div>
          )}
          {mode==="parametric" && (
            <div style={{marginTop:"10px",padding:"10px",background:UI.panel,border:`1px solid ${UI.border}`,borderRadius:"4px"}}>
              <div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"6px"}}>LIVE FORMULA</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"4px"}}>
                {[["θ",`${theta}°`],["cos θ",Math.cos(theta*Math.PI/180).toFixed(3)],["sin θ",Math.sin(theta*Math.PI/180).toFixed(3)],["w×h",`${w}×${h}`],["a",`(${2*w},0)`],["b",`(${w},${2*h})`],["r_in",`${rIn}px`],["r_out",`${rOut}px`]].map(([k,v])=>(
                  <div key={k} style={{display:"flex",justifyContent:"space-between",padding:"3px 5px",background:UI.bg,borderRadius:"2px",border:`1px solid ${UI.border2}`}}>
                    <span style={{fontSize:"8px",color:UI.dimmer}}>{k}</span>
                    <span style={{fontSize:"9px",color:UI.gold,fontWeight:"bold"}}>{v}</span>
                  </div>
                ))}
              </div>
              <div style={{marginTop:"6px",fontSize:"9px",color:UI.dimmer,lineHeight:"1.7"}}>
                DXF reference: w=1mm, h=2mm, θ=45° — use those values to match the CAD file exactly.
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
