  const[c0,setC0]=useState(COLORS[0].fill);const[c1,setC1]=useState(COLORS[1].fill);const[c2,setC2]=useState(COLORS[2].fill);
  const colors={0:c0,1:c1,2:c2,3:COLORS[3].fill};
