          <div style={{marginBottom:"10px"}}><div style={{fontSize:"9px",letterSpacing:"2px",color:UI.dim,marginBottom:"5px"}}>SYMMETRY</div>{[["None","N"],["Horiz","H"],["Vert","V"],["4-Way","4"]].map(([l,v])=>(<div key={v} onClick={()=>setSym(v)} style={{padding:"3px 6px",marginBottom:"3px",cursor:"pointer",fontSize:"9px",border:sym===v?"1px solid #c9a96e":"1px solid #2a1e0a",borderRadius:"3px",background:sym===v?"#1e1508":"transparent",color:sym===v?UI.gold:UI.dim}}>{l}</div>))}</div>
